// NODE: Parse message + get image URL via Telegram Bot API
// Accepts: photo OR document (file) with caption as prompt
// Output: imageUrl, prompt, chatId

const _https = require('https');
const { URL } = require('url');

function fetch(url, opts = {}, _redirectCount = 0) {
  return new Promise((resolve, reject) => {
    if (_redirectCount > 5) return reject(new Error('Too many redirects'));
    const u = new URL(url);
    const body = opts.body || null;
    const ro = {
      hostname: u.hostname,
      port: u.port || undefined,
      path: u.pathname + u.search,
      method: opts.method || 'GET',
      headers: { ...(opts.headers || {}) },
    };
    if (body) ro.headers['Content-Length'] = Buffer.byteLength(body);
    const req = _https.request(ro, res => {
      if ([301, 302, 307, 308].includes(res.statusCode) && res.headers.location) {
        res.resume();
        return fetch(res.headers.location, opts, _redirectCount + 1).then(resolve).catch(reject);
      }
      const chunks = [];
      res.on('data', c => chunks.push(c));
      res.on('end', () => {
        const buf = Buffer.concat(chunks);
        resolve({
          ok: res.statusCode >= 200 && res.statusCode < 300,
          status: res.statusCode,
          json: () => Promise.resolve(JSON.parse(buf.toString())),
          text: () => Promise.resolve(buf.toString()),
        });
      });
    });
    req.on('error', reject);
    if (body) req.write(body);
    req.end();
  });
}

const botToken = $env.TELEGRAM_BOT_TOKEN || '';
if (!botToken) throw new Error('TELEGRAM_BOT_TOKEN env variable not set');

const msg = $input.first().json.message || $input.first().json;

// Extract file_id from photo OR document
let fileId = null;
const photos = msg.photo || [];
if (photos.length > 0) {
  // Sent as photo — pick largest resolution
  fileId = photos[photos.length - 1].file_id;
} else if (msg.document && msg.document.mime_type && msg.document.mime_type.startsWith('image/')) {
  // Sent as file/document (image)
  fileId = msg.document.file_id;
}

if (!fileId) {
  throw new Error('No image found. Send a photo or image file with a caption as prompt.');
}

// Extract prompt from caption
const prompt = (msg.caption || '').trim();
if (!prompt) {
  throw new Error('No prompt found. Add a caption to the photo.');
}

const chatId = msg.chat.id;

// Call Telegram getFile API to get file_path
const fileRes = await fetch('https://api.telegram.org/bot' + botToken + '/getFile', {
  method: 'POST',
  headers: { 'Content-Type': 'application/json' },
  body: JSON.stringify({ file_id: fileId }),
});

if (!fileRes.ok) {
  const errText = await fileRes.text();
  throw new Error('Telegram getFile failed: ' + fileRes.status + ' ' + errText);
}

const fileData = await fileRes.json();
if (!fileData.ok || !fileData.result || !fileData.result.file_path) {
  throw new Error('Telegram getFile returned no file_path');
}

const imageUrl = 'https://api.telegram.org/file/bot' + botToken + '/' + fileData.result.file_path;

return [{
  json: {
    imageUrl,
    prompt,
    chatId
  }
}];

