// NODE: Call fal.ai Seedance v1.5 Pro — Image to Video
// Settings: 9:16, 720p, 10s, camera fixed, no safety checker, no audio

const _https = require('https');
const _http = require('http');
const { URL } = require('url');

function fetch(url, opts = {}, _redirectCount = 0) {
  return new Promise((resolve, reject) => {
    if (_redirectCount > 5) return reject(new Error('Too many redirects'));
    const u = new URL(url);
    const lib = u.protocol === 'https:' ? _https : _http;
    const body = opts.body || null;
    const ro = {
      hostname: u.hostname,
      port: u.port || undefined,
      path: u.pathname + u.search,
      method: opts.method || 'GET',
      headers: { ...(opts.headers || {}) },
    };
    if (body) ro.headers['Content-Length'] = Buffer.byteLength(body);
    const req = lib.request(ro, res => {
      if ([301, 302, 307, 308].includes(res.statusCode) && res.headers.location) {
        res.resume();
        const redirectUrl = res.headers.location.startsWith('http')
          ? res.headers.location
          : u.protocol + '//' + u.host + res.headers.location;
        return fetch(redirectUrl, opts, _redirectCount + 1).then(resolve).catch(reject);
      }
      const chunks = [];
      res.on('data', c => chunks.push(c));
      res.on('end', () => {
        const buf = Buffer.concat(chunks);
        resolve({
          ok: res.statusCode >= 200 && res.statusCode < 300,
          status: res.statusCode,
          text: () => Promise.resolve(buf.toString()),
          json: () => Promise.resolve(JSON.parse(buf.toString())),
        });
      });
    });
    req.on('error', reject);
    if (body) req.write(body);
    req.end();
  });
}

const FAL_KEY = $env.FAL_KEY || '';
if (!FAL_KEY) throw new Error('FAL_KEY env variable not set');

const ENDPOINT = 'fal-ai/bytedance/seedance/v1.5/pro/image-to-video';
const BASE_URL = 'https://queue.fal.run';
const POLL_INTERVAL = 8000;
const TIMEOUT = 600000;

const { imageUrl, prompt, chatId } = $input.first().json;

// Submit job
const submitRes = await fetch(BASE_URL + '/' + ENDPOINT, {
  method: 'POST',
  headers: {
    'Authorization': 'Key ' + FAL_KEY,
    'Content-Type': 'application/json',
  },
  body: JSON.stringify({
    image_url: imageUrl,
    prompt: prompt,
    aspect_ratio: '9:16',
    resolution: '720p',
    duration: '10',
    camera_fixed: true,
    enable_safety_checker: false,
    generate_audio: false,
    seed: -1
  }),
});

if (!submitRes.ok) {
  const errText = await submitRes.text();
  throw new Error('fal.ai submit failed: ' + submitRes.status + ' ' + errText);
}

const submitData = await submitRes.json();
const requestId = submitData.request_id;

// Poll for completion
const startTime = Date.now();
let result = null;

while (Date.now() - startTime < TIMEOUT) {
  await new Promise(r => setTimeout(r, POLL_INTERVAL));

  const statusRes = await fetch(
    BASE_URL + '/' + ENDPOINT + '/requests/' + requestId + '/status',
    { headers: { 'Authorization': 'Key ' + FAL_KEY } }
  );

  if (!statusRes.ok) continue;
  const statusData = await statusRes.json();

  if (statusData.status === 'COMPLETED') {
    const resultRes = await fetch(
      BASE_URL + '/' + ENDPOINT + '/requests/' + requestId,
      { headers: { 'Authorization': 'Key ' + FAL_KEY } }
    );
    if (!resultRes.ok) throw new Error('fal.ai result fetch failed: ' + resultRes.status);
    result = await resultRes.json();
    break;
  }

  if (statusData.status === 'FAILED') {
    throw new Error('fal.ai job failed: ' + JSON.stringify(statusData));
  }
}

if (!result) throw new Error('fal.ai timeout after ' + (TIMEOUT / 1000) + 's');
if (!result.video || !result.video.url) throw new Error('No video URL in result');

return [{
  json: {
    videoUrl: result.video.url,
    seed: result.seed,
    chatId,
    prompt
  }
}];

